#version 330 core

layout(location = 0) in vec3 aPos;
layout(location = 1) in vec2 aTexCoord;
layout(location = 2) in vec3 aNormal;

out vec2 TexCoord;
out vec3 Normal;
out vec3 FragPos;
out float Diffuse;

uniform mat4 model;
uniform mat4 view;
uniform mat4 projection;

void main()
{
    FragPos = vec3(model * vec4(aPos, 1.0));
    TexCoord = aTexCoord;

    // Блочное освещение (по нормалям осей)
    vec3 worldNormal = normalize(mat3(model) * aNormal);
    Diffuse = max(dot(worldNormal, vec3(0.0, 1.0, 0.0)), 0.0);
    Diffuse = floor(Diffuse * 3.0) / 3.0; // Квантование освещения

    gl_Position = projection * view * vec4(FragPos, 1.0);
}

#version 330 core

in vec2 TexCoord;
in float Diffuse;
out vec4 FragColor;

uniform sampler2D textureAtlas;
uniform float ambient;

void main()
{
    vec4 color = texture(textureAtlas, TexCoord);

    // Альфа-тест для прозрачных пикселей
    if(color.a < 0.5)
        discard;

    // Применяем освещение
    color.rgb *= (ambient + Diffuse);

    // Пост-обработка для пикселизации (опционально)
    color.rgb = floor(color.rgb * 4.0) / 4.0;

    FragColor = color;
}
